import SwiftUI

/// Tappable profile mention chip. Renders `@displayName` and, when an avatar
/// URL is available, a small circular avatar alongside the name. Falls back to
/// a deterministic identicon color block when no URL is provided.
///
/// Depends on `swiftui/content-core` for the `NostrContentRenderer` environment
/// (colors + callbacks).
public struct NostrMentionChip: View {
    public var pubkey: String
    public var displayName: String?
    public var avatarUrl: URL?
    public var showsAvatar: Bool

    @Environment(\.nostrContentRenderer) private var renderer

    public init(
        pubkey: String,
        displayName: String? = nil,
        avatarUrl: URL? = nil,
        showsAvatar: Bool = true
    ) {
        self.pubkey = pubkey
        self.displayName = displayName
        self.avatarUrl = avatarUrl
        self.showsAvatar = showsAvatar
    }

    public var body: some View {
        Button {
            renderer.callbacks.onMentionTap(pubkey)
        } label: {
            HStack(spacing: 4) {
                if showsAvatar {
                    avatar
                }
                Text("@\(label)")
                    .foregroundStyle(renderer.mentionColor)
                    .fontWeight(.semibold)
                    .lineLimit(1)
            }
        }
        .buttonStyle(.plain)
        .accessibilityLabel("Mention of \(label)")
    }

    private var label: String {
        if let displayName, !displayName.isEmpty {
            return displayName
        }
        return shortPubkey(pubkey)
    }

    @ViewBuilder
    private var avatar: some View {
        if let avatarUrl {
            AsyncImage(url: avatarUrl) { phase in
                switch phase {
                case .success(let image):
                    image
                        .resizable()
                        .scaledToFill()
                case .failure:
                    fallback
                case .empty:
                    fallback
                @unknown default:
                    fallback
                }
            }
            .frame(width: 16, height: 16)
            .clipShape(Circle())
        } else {
            fallback
        }
    }

    private var fallback: some View {
        ZStack {
            Circle()
                .fill(NostrIdenticon.color(forPubkey: pubkey))
            Text(NostrIdenticon.initials(forPubkey: pubkey))
                .font(.system(size: 8, weight: .semibold))
                .foregroundStyle(.white)
        }
        .frame(width: 16, height: 16)
    }

    private func shortPubkey(_ value: String) -> String {
        guard value.count > 12 else { return value }
        return "\(value.prefix(8))…\(value.suffix(4))"
    }
}

import SwiftUI

/// Photo-style grid layout for an ordered list of image URLs.
///
/// Layout rules:
///   • 1 image  — full-width
///   • 2 images — side-by-side, equal halves
///   • 3 images — one large on the left, two stacked on the right
///   • 4+       — 2×2 grid; last visible cell carries a "+N more" overlay
///
/// Tapping a cell calls `NostrContentCallbacks.onImageTap` from the
/// `NostrContentRenderer` environment. Apps that want different routing can
/// provide a `tapHandler` closure to override the environment callback.
///
/// Depends on `swiftui/content-core`.
public struct NostrMediaGrid: View {
    public var imageUrls: [URL]
    public var aspectRatio: CGFloat
    public var cornerRadius: CGFloat
    public var tapHandler: ((URL) -> Void)?

    @Environment(\.nostrContentRenderer) private var renderer

    public init(
        imageUrls: [URL],
        aspectRatio: CGFloat = 16.0 / 9.0,
        cornerRadius: CGFloat = 10,
        tapHandler: ((URL) -> Void)? = nil
    ) {
        self.imageUrls = imageUrls
        self.aspectRatio = aspectRatio
        self.cornerRadius = cornerRadius
        self.tapHandler = tapHandler
    }

    public var body: some View {
        switch imageUrls.count {
        case 0:
            EmptyView()
        case 1:
            singleLayout(imageUrls[0])
        case 2:
            doubleLayout(left: imageUrls[0], right: imageUrls[1])
        case 3:
            tripleLayout(primary: imageUrls[0], secondary: imageUrls[1], tertiary: imageUrls[2])
        default:
            quadLayout(imageUrls)
        }
    }

    @ViewBuilder
    private func singleLayout(_ url: URL) -> some View {
        cell(for: url, overlay: nil)
            .aspectRatio(aspectRatio, contentMode: .fit)
    }

    @ViewBuilder
    private func doubleLayout(left: URL, right: URL) -> some View {
        HStack(spacing: 2) {
            cell(for: left, overlay: nil)
            cell(for: right, overlay: nil)
        }
        .aspectRatio(aspectRatio, contentMode: .fit)
    }

    @ViewBuilder
    private func tripleLayout(primary: URL, secondary: URL, tertiary: URL) -> some View {
        HStack(spacing: 2) {
            cell(for: primary, overlay: nil)
            VStack(spacing: 2) {
                cell(for: secondary, overlay: nil)
                cell(for: tertiary, overlay: nil)
            }
        }
        .aspectRatio(aspectRatio, contentMode: .fit)
    }

    @ViewBuilder
    private func quadLayout(_ urls: [URL]) -> some View {
        let visible = Array(urls.prefix(4))
        let extra = urls.count - visible.count
        VStack(spacing: 2) {
            HStack(spacing: 2) {
                cell(for: visible[0], overlay: nil)
                cell(for: visible[1], overlay: nil)
            }
            HStack(spacing: 2) {
                cell(for: visible[2], overlay: nil)
                cell(
                    for: visible[3],
                    overlay: extra > 0 ? "+\(extra)" : nil
                )
            }
        }
        .aspectRatio(1, contentMode: .fit)
    }

    @ViewBuilder
    private func cell(for url: URL, overlay: String?) -> some View {
        Button {
            (tapHandler ?? renderer.callbacks.onImageTap)(url)
        } label: {
            AsyncImage(url: url) { phase in
                switch phase {
                case .empty:
                    placeholder
                case .success(let image):
                    image
                        .resizable()
                        .scaledToFill()
                case .failure:
                    errorTile
                @unknown default:
                    placeholder
                }
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
            .clipped()
            .overlay {
                if let overlay {
                    ZStack {
                        Color.black.opacity(0.45)
                        Text(overlay)
                            .font(.title3.weight(.semibold))
                            .foregroundStyle(.white)
                    }
                }
            }
            .clipShape(RoundedRectangle(cornerRadius: cornerRadius))
        }
        .buttonStyle(.plain)
        .accessibilityLabel("Image")
    }

    private var placeholder: some View {
        ZStack {
            renderer.codeBackgroundColor
            ProgressView()
        }
    }

    private var errorTile: some View {
        ZStack {
            renderer.codeBackgroundColor
            Image(systemName: "photo")
                .foregroundStyle(renderer.placeholderColor)
        }
    }
}

import SwiftUI

/// Variant of the quote/embed card. Each style is a stable rendering contract
/// the embedding app can switch between without re-deriving data.
public enum NostrQuoteCardVariant: Equatable {
    /// Single-line `View quote` affordance; expands to `.rich` on tap when the
    /// app wires the `onExpand` closure.
    case collapsed
    /// Author + truncated content text, framed only by a border.
    case compact
    /// Author avatar stub + name + truncated content + optional media thumb.
    case rich
    /// "Content unavailable" placeholder, surfaces `unresolvedUri` to the user.
    case missing
}

/// Data model the embedding app populates per quote card. The card view is
/// pure — it never fetches network state. Apps pass a closure or environment
/// value into their data layer to hydrate `NostrQuoteCardModel` instances.
public struct NostrQuoteCardModel: Equatable {
    public var id: String
    public var unresolvedUri: String?
    public var authorPubkey: String?
    public var authorDisplayName: String?
    public var authorAvatarUrl: URL?
    public var content: String
    public var mediaThumbnailUrl: URL?
    public var createdAtDisplay: String?

    public init(
        id: String,
        unresolvedUri: String? = nil,
        authorPubkey: String? = nil,
        authorDisplayName: String? = nil,
        authorAvatarUrl: URL? = nil,
        content: String = "",
        mediaThumbnailUrl: URL? = nil,
        createdAtDisplay: String? = nil
    ) {
        self.id = id
        self.unresolvedUri = unresolvedUri
        self.authorPubkey = authorPubkey
        self.authorDisplayName = authorDisplayName
        self.authorAvatarUrl = authorAvatarUrl
        self.content = content
        self.mediaThumbnailUrl = mediaThumbnailUrl
        self.createdAtDisplay = createdAtDisplay
    }

    public static let missing = NostrQuoteCardModel(id: "")
}

/// Reusable quote / embedded-event card. The app is responsible for hydrating
/// the model; the card only renders.
public struct NostrQuoteCard: View {
    public var model: NostrQuoteCardModel
    public var variant: NostrQuoteCardVariant
    public var onTap: (() -> Void)?
    public var onExpand: (() -> Void)?

    @Environment(\.nostrContentRenderer) private var renderer

    public init(
        model: NostrQuoteCardModel,
        variant: NostrQuoteCardVariant = .rich,
        onTap: (() -> Void)? = nil,
        onExpand: (() -> Void)? = nil
    ) {
        self.model = model
        self.variant = variant
        self.onTap = onTap
        self.onExpand = onExpand
    }

    public var body: some View {
        switch variant {
        case .collapsed: collapsedBody
        case .compact:   compactBody
        case .rich:      richBody
        case .missing:   missingBody
        }
    }

    // MARK: variants

    private var collapsedBody: some View {
        Button {
            (onExpand ?? onTap ?? defaultTap)()
        } label: {
            HStack(spacing: 8) {
                Image(systemName: "quote.bubble")
                    .foregroundStyle(renderer.linkColor)
                Text("View quote")
                    .font(.callout.weight(.semibold))
                    .foregroundStyle(renderer.linkColor)
                Spacer(minLength: 0)
            }
            .padding(10)
            .frame(maxWidth: .infinity, alignment: .leading)
            .background(renderer.quoteBackgroundColor, in: RoundedRectangle(cornerRadius: 8))
            .overlay(border)
        }
        .buttonStyle(.plain)
        .accessibilityLabel("View quoted post")
    }

    private var compactBody: some View {
        cardButton {
            VStack(alignment: .leading, spacing: 4) {
                Text("@\(authorLabel)")
                    .font(.caption.weight(.semibold))
                    .foregroundStyle(renderer.textColor)
                Text(truncated(model.content, limit: 140))
                    .font(.callout)
                    .foregroundStyle(renderer.textColor)
                    .lineLimit(3)
            }
        }
    }

    private var richBody: some View {
        cardButton {
            VStack(alignment: .leading, spacing: 8) {
                HStack(spacing: 8) {
                    avatar
                    VStack(alignment: .leading, spacing: 1) {
                        Text("@\(authorLabel)")
                            .font(.caption.weight(.semibold))
                            .foregroundStyle(renderer.textColor)
                            .lineLimit(1)
                        if let display = model.createdAtDisplay {
                            Text(display)
                                .font(.caption2.monospaced())
                                .foregroundStyle(renderer.secondaryTextColor)
                                .lineLimit(1)
                        }
                    }
                    Spacer(minLength: 0)
                    Image(systemName: "chevron.right")
                        .font(.caption2.weight(.semibold))
                        .foregroundStyle(renderer.secondaryTextColor)
                }
                if !model.content.isEmpty {
                    Text(truncated(model.content, limit: 240))
                        .font(.callout)
                        .foregroundStyle(renderer.textColor)
                        .lineLimit(6)
                }
                if let thumb = model.mediaThumbnailUrl {
                    thumbnail(thumb)
                }
            }
        }
    }

    private var missingBody: some View {
        HStack(spacing: 10) {
            Image(systemName: "exclamationmark.bubble")
                .font(.callout.weight(.semibold))
                .foregroundStyle(renderer.placeholderColor)
            VStack(alignment: .leading, spacing: 2) {
                Text("Content unavailable")
                    .font(.caption.weight(.semibold))
                    .foregroundStyle(renderer.textColor)
                if let uri = model.unresolvedUri, !uri.isEmpty {
                    Text(uri)
                        .font(.caption2.monospaced())
                        .foregroundStyle(renderer.secondaryTextColor)
                        .lineLimit(1)
                        .truncationMode(.middle)
                }
            }
            Spacer(minLength: 0)
        }
        .padding(10)
        .frame(maxWidth: .infinity, alignment: .leading)
        .background(renderer.quoteBackgroundColor, in: RoundedRectangle(cornerRadius: 8))
        .overlay(border)
    }

    // MARK: helpers

    private func cardButton<Content: View>(@ViewBuilder content: () -> Content) -> some View {
        Button {
            (onTap ?? defaultTap)()
        } label: {
            content()
                .padding(10)
                .frame(maxWidth: .infinity, alignment: .leading)
                .background(renderer.quoteBackgroundColor, in: RoundedRectangle(cornerRadius: 8))
                .overlay(border)
        }
        .buttonStyle(.plain)
        .accessibilityLabel("Open quoted post")
    }

    private func defaultTap() {
        renderer.callbacks.onEventRefTap(model.id)
    }

    @ViewBuilder
    private var avatar: some View {
        if let avatarUrl = model.authorAvatarUrl {
            AsyncImage(url: avatarUrl) { phase in
                switch phase {
                case .success(let image):
                    image.resizable().scaledToFill()
                default:
                    avatarFallback
                }
            }
            .frame(width: 26, height: 26)
            .clipShape(Circle())
        } else {
            avatarFallback
        }
    }

    private var avatarFallback: some View {
        ZStack {
            Circle()
                .fill(NostrIdenticon.color(forPubkey: model.authorPubkey ?? model.id))
            Text(NostrIdenticon.initials(forPubkey: model.authorPubkey ?? model.id))
                .font(.system(size: 12, weight: .semibold))
                .foregroundStyle(.white)
        }
        .frame(width: 26, height: 26)
    }

    private func thumbnail(_ url: URL) -> some View {
        AsyncImage(url: url) { phase in
            switch phase {
            case .success(let image):
                image
                    .resizable()
                    .scaledToFill()
                    .frame(maxWidth: .infinity, maxHeight: 160)
                    .clipped()
                    .clipShape(RoundedRectangle(cornerRadius: 6))
            default:
                RoundedRectangle(cornerRadius: 6)
                    .fill(renderer.codeBackgroundColor)
                    .frame(maxWidth: .infinity, minHeight: 60, maxHeight: 120)
            }
        }
    }

    private var border: some View {
        RoundedRectangle(cornerRadius: 8)
            .stroke(renderer.quoteBorderColor, lineWidth: 0.5)
    }

    private var authorLabel: String {
        if let display = model.authorDisplayName, !display.isEmpty {
            return display
        }
        if let pubkey = model.authorPubkey, !pubkey.isEmpty {
            return shortPubkey(pubkey)
        }
        return shortPubkey(model.id)
    }

    private func truncated(_ value: String, limit: Int) -> String {
        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
        guard trimmed.count > limit else { return trimmed }
        return "\(trimmed.prefix(limit))…"
    }

    private func shortPubkey(_ value: String) -> String {
        guard value.count > 12 else { return value }
        return "\(value.prefix(8))…\(value.suffix(4))"
    }
}

import SwiftUI

/// SwiftUI renderer for a `ContentTreeWire`. Walks `tree.roots`, flattens the
/// arena into block-level groups via `nostrContentGroups`, and renders each
/// block (paragraph/heading/media/code/list/quote/rule/image/event-ref/
/// placeholder) with the inline-text concatenation pattern proven by Chirp's
/// `NoteContentView`.
///
/// Data injection contract:
///   • Theming + tap callbacks come from `NostrContentRenderer` in the
///     SwiftUI environment (see `swiftui/content-core`).
///   • Mention display labels are provided by the app via `mentionLabel`.
///   • Quote/embed cards are app-owned: the app passes a `quoteCardProvider`
///     closure that returns a `NostrQuoteCardModel` for an event-ref URI.
///     When `nil`, the view falls back to a `.collapsed` quote card.
public struct NostrContentView: View {
    public var tree: ContentTreeWire
    public var font: Font
    public var mentionLabel: (NostrWireUri) -> String
    public var quoteCardProvider: ((NostrWireUri) -> NostrQuoteCardModel?)?

    @Environment(\.nostrContentRenderer) private var renderer

    public init(
        tree: ContentTreeWire,
        font: Font = .body,
        mentionLabel: @escaping (NostrWireUri) -> String = NostrContentView.defaultMentionLabel,
        quoteCardProvider: ((NostrWireUri) -> NostrQuoteCardModel?)? = nil
    ) {
        self.tree = tree
        self.font = font
        self.mentionLabel = mentionLabel
        self.quoteCardProvider = quoteCardProvider
    }

    public var body: some View {
        let groups = nostrContentGroups(tree)
        if groups.isEmpty {
            EmptyView()
        } else {
            VStack(alignment: .leading, spacing: 8) {
                ForEach(Array(groups.enumerated()), id: \.offset) { _, group in
                    groupView(group)
                }
            }
        }
    }

    // MARK: - Group dispatch

    @ViewBuilder
    private func groupView(_ group: NostrContentGroup) -> some View {
        switch group {
        case .inline(let level, let children):
            inlineGroup(level: level, children: children)
        case .media(let urls, let kind):
            mediaGroup(urls: urls, kind: kind)
        case .eventRef(let uri):
            eventRefView(uri)
        case .codeBlock(let info, let body):
            codeBlockView(info: info, body: body)
        case .blockQuote(let children):
            blockQuoteView(children: children)
        case .list(let orderedStart, let items):
            listView(orderedStart: orderedStart, items: items)
        case .rule:
            ruleView
        case .image(let alt, let title, let src):
            imageBlockView(alt: alt, title: title, src: src)
        case .placeholder(let reason):
            placeholderChip(reason: reason)
        }
    }

    @ViewBuilder
    private func inlineGroup(level: NostrContentInlineLevel, children: [UInt32]) -> some View {
        let concatenated = children.reduce(Text("")) { acc, child in
            acc + inlineText(child)
        }
        switch level {
        case .paragraph:
            concatenated
                .font(font)
                .foregroundStyle(renderer.textColor)
                .fixedSize(horizontal: false, vertical: true)
        case .heading(let lvl):
            concatenated
                .font(headingFont(for: lvl))
                .foregroundStyle(renderer.textColor)
                .fixedSize(horizontal: false, vertical: true)
        }
    }

    // MARK: - Inline text concatenation

    /// Convert one arena node into a `Text` value that can be `+`-concatenated
    /// with neighbouring runs. Recursive children (emphasis/strong/link/heading
    /// /paragraph) are walked here so the whole inline subtree collapses to a
    /// single `Text`.
    public func inlineText(_ index: UInt32) -> Text {
        if index == nostrContentNewlineSentinel { return Text("\n") }
        guard let node = tree.node(at: index) else { return Text("") }
        switch node {
        case .text(let value):
            return Text(value)
        case .mention(let uri):
            return Text("@\(mentionLabel(uri))")
                .foregroundStyle(renderer.mentionColor)
                .bold()
        case .eventRef(let uri):
            return Text("↩ \(shortEntity(uri.primaryId))")
                .foregroundStyle(renderer.linkColor)
                .bold()
        case .hashtag(let tag):
            return Text("#\(tag)")
                .foregroundStyle(renderer.hashtagColor)
                .bold()
        case .url(let value):
            return Text(value).foregroundStyle(renderer.linkColor)
        case .emoji(let shortcode, _):
            return Text(":\(shortcode):")
        case .invoice:
            return Text("⚡ invoice").foregroundStyle(renderer.linkColor)
        case .emphasis(let children):
            return children.reduce(Text("")) { $0 + inlineText($1).italic() }
        case .strong(let children):
            return children.reduce(Text("")) { $0 + inlineText($1).bold() }
        case .inlineCode(let value):
            return Text(value).font(.system(.body, design: .monospaced))
        case .link(let children, let href):
            let label = children.reduce(Text("")) { $0 + inlineText($1) }
            if let href, !href.isEmpty {
                return label
                    .foregroundStyle(renderer.linkColor)
                    .underline()
            }
            return label
        case .image(let alt, _, _):
            return Text(alt.isEmpty ? "[image]" : "[\(alt)]")
                .foregroundStyle(renderer.placeholderColor)
        case .softBreak:
            return Text(" ")
        case .hardBreak:
            return Text("\n")
        case .paragraph(let children),
             .heading(_, let children),
             .blockQuote(let children):
            return children.reduce(Text("")) { $0 + inlineText($1) }
        case .list, .codeBlock, .rule, .media, .placeholder:
            // Block-level — should never appear inside an inline reduce. Emit
            // nothing rather than break the text concatenation.
            return Text("")
        }
    }

    // MARK: - Block builders

    @ViewBuilder
    private func mediaGroup(urls: [String], kind: NostrMediaKind) -> some View {
        switch kind {
        case .image:
            let parsed = urls.compactMap(URL.init(string:))
            if !parsed.isEmpty {
                NostrMediaGrid(imageUrls: parsed)
            }
        case .video, .audio:
            if let first = urls.first.flatMap(URL.init(string:)) {
                mediaRow(first, systemImage: kind == .audio ? "speaker.wave.2.fill" : "play.rectangle.fill")
            }
        }
    }

    private func mediaRow(_ url: URL, systemImage: String) -> some View {
        Button {
            renderer.callbacks.onLinkTap(url)
        } label: {
            HStack(spacing: 10) {
                Image(systemName: systemImage)
                    .font(.title2)
                    .foregroundStyle(renderer.linkColor)
                Text(url.lastPathComponent)
                    .font(.caption.monospaced())
                    .foregroundStyle(renderer.secondaryTextColor)
                    .lineLimit(1)
                Spacer(minLength: 0)
            }
            .padding(12)
            .frame(maxWidth: .infinity)
            .background(renderer.codeBackgroundColor, in: RoundedRectangle(cornerRadius: 8))
        }
        .buttonStyle(.plain)
    }

    private func eventRefView(_ uri: NostrWireUri) -> some View {
        // Variant selection is a three-branch decision so the `.missing`
        // variant is reachable:
        //   • no provider wired       → `.collapsed` (View quote affordance)
        //   • provider returned model → `.rich`
        //   • provider returned nil   → `.missing` (Content unavailable + URI)
        let providedModel = quoteCardProvider?(uri)
        let variant: NostrQuoteCardVariant
        let model: NostrQuoteCardModel
        if quoteCardProvider == nil {
            variant = .collapsed
            model = NostrQuoteCardModel(id: uri.primaryId, unresolvedUri: uri.uri)
        } else if let providedModel {
            variant = .rich
            model = providedModel
        } else {
            variant = .missing
            model = NostrQuoteCardModel(id: uri.primaryId, unresolvedUri: uri.uri)
        }
        return NostrQuoteCard(
            model: model,
            variant: variant,
            onTap: { renderer.callbacks.onEventRefTap(uri.primaryId) }
        )
    }

    private func codeBlockView(info: String?, body: String) -> some View {
        VStack(alignment: .leading, spacing: 4) {
            if let info, !info.isEmpty {
                Text(info)
                    .font(.caption2.monospaced())
                    .foregroundStyle(renderer.secondaryTextColor)
            }
            Text(body)
                .font(.system(.callout, design: .monospaced))
                .foregroundStyle(renderer.textColor)
                .frame(maxWidth: .infinity, alignment: .leading)
        }
        .padding(10)
        .background(renderer.codeBackgroundColor, in: RoundedRectangle(cornerRadius: 6))
    }

    private func blockQuoteView(children: [UInt32]) -> some View {
        let text = children.reduce(Text("")) { $0 + inlineText($1) }
        return HStack(spacing: 10) {
            Rectangle()
                .fill(renderer.quoteBorderColor)
                .frame(width: 3)
            text
                .font(font.italic())
                .foregroundStyle(renderer.secondaryTextColor)
                .frame(maxWidth: .infinity, alignment: .leading)
        }
        .padding(.vertical, 4)
        .frame(maxWidth: .infinity, alignment: .leading)
    }

    @ViewBuilder
    private func listView(orderedStart: UInt64?, items: [[UInt32]]) -> some View {
        VStack(alignment: .leading, spacing: 4) {
            ForEach(Array(items.enumerated()), id: \.offset) { offset, children in
                HStack(alignment: .firstTextBaseline, spacing: 8) {
                    Text(marker(orderedStart: orderedStart, offset: offset))
                        .font(font)
                        .foregroundStyle(renderer.secondaryTextColor)
                    children.reduce(Text("")) { $0 + inlineText($1) }
                        .font(font)
                        .foregroundStyle(renderer.textColor)
                        .frame(maxWidth: .infinity, alignment: .leading)
                }
            }
        }
    }

    private func marker(orderedStart: UInt64?, offset: Int) -> String {
        if let orderedStart {
            return "\(orderedStart + UInt64(offset))."
        }
        return "•"
    }

    private var ruleView: some View {
        Rectangle()
            .fill(renderer.quoteBorderColor)
            .frame(height: 1)
            .padding(.vertical, 4)
    }

    private func imageBlockView(alt: String, title: String?, src: String?) -> some View {
        if let src, let url = URL(string: src) {
            return AnyView(
                NostrMediaGrid(imageUrls: [url])
                    .accessibilityLabel(title ?? alt)
            )
        }
        return AnyView(
            Text(alt.isEmpty ? "[image]" : "[\(alt)]")
                .font(.caption)
                .foregroundStyle(renderer.placeholderColor)
        )
    }

    private func placeholderChip(reason: NostrWirePlaceholderReason) -> some View {
        let label: String
        let icon: String
        switch reason {
        case .depthLimit:
            label = "Nested content collapsed"
            icon = "chevron.down.square"
        case .unresolvedUri:
            label = "Unresolved reference"
            icon = "questionmark.square.dashed"
        }
        return HStack(spacing: 6) {
            Image(systemName: icon)
                .foregroundStyle(renderer.placeholderColor)
            Text(label)
                .font(.caption.weight(.semibold))
                .foregroundStyle(renderer.placeholderColor)
        }
        .padding(.horizontal, 8)
        .padding(.vertical, 4)
        .background(renderer.codeBackgroundColor, in: Capsule())
    }

    // MARK: - Defaults / helpers

    public static func defaultMentionLabel(_ uri: NostrWireUri) -> String {
        let value = uri.primaryId
        guard value.count > 12 else { return value }
        return "\(value.prefix(8))…\(value.suffix(4))"
    }

    private func headingFont(for level: UInt8) -> Font {
        switch level {
        case 1: return .largeTitle.weight(.bold)
        case 2: return .title.weight(.bold)
        case 3: return .title2.weight(.semibold)
        case 4: return .title3.weight(.semibold)
        case 5: return .headline
        default: return .subheadline.weight(.semibold)
        }
    }

    private func shortEntity(_ value: String) -> String {
        guard value.count > 12 else { return value }
        return "\(value.prefix(8))…\(value.suffix(4))"
    }
}

import SwiftUI

/// Block-level group produced by walking the roots of a `ContentTreeWire`.
/// `NostrContentView` consumes these in order; the grouping logic exists in a
/// separate file so the renderer view itself stays focused on layout.
public enum NostrContentGroup: Equatable {
    /// Inline runs that should be concatenated with `Text + Text`. The
    /// `[UInt32]` values are node indices; `.init(UInt32.max)` is a sentinel
    /// trailing newline used to separate adjacent paragraphs/headings.
    case inline(level: NostrContentInlineLevel, children: [UInt32])
    case media(urls: [String], kind: NostrMediaKind)
    case eventRef(NostrWireUri)
    case codeBlock(info: String?, body: String)
    case blockQuote(children: [UInt32])
    case list(orderedStart: UInt64?, items: [[UInt32]])
    case rule
    case image(alt: String, title: String?, src: String?)
    case placeholder(reason: NostrWirePlaceholderReason)
}

/// Display level for inline-text groups; lets the renderer pick paragraph vs
/// heading typography without re-walking the arena.
public enum NostrContentInlineLevel: Equatable {
    case paragraph
    case heading(level: UInt8)
}

/// Sentinel index used to inject a trailing newline between contiguous inline
/// groups (paragraph/heading). Index `UInt32.max` cannot reference a real
/// arena slot — the bounds check in `node(at:)` rejects it — so renderers can
/// safely treat it as a newline marker.
public let nostrContentNewlineSentinel: UInt32 = .max

/// Flatten the document into a sequence of block-level groups. Mirrors the
/// shape of `noteContentGroups` in Chirp's `NoteEntityViews.swift`.
public func nostrContentGroups(_ tree: ContentTreeWire) -> [NostrContentGroup] {
    var groups: [NostrContentGroup] = []
    var pendingChildren: [UInt32] = []
    var pendingLevel: NostrContentInlineLevel = .paragraph

    func flush() {
        if !pendingChildren.isEmpty {
            groups.append(.inline(level: pendingLevel, children: pendingChildren))
            pendingChildren = []
            pendingLevel = .paragraph
        }
    }

    func appendInline(level: NostrContentInlineLevel, children: [UInt32]) {
        // Different inline-block levels can't share a paragraph; flush first.
        if !pendingChildren.isEmpty, pendingLevel != level {
            flush()
        }
        pendingLevel = level

        let startCount = pendingChildren.count
        for child in children {
            guard let childNode = tree.node(at: child) else { continue }
            if case .eventRef(let uri) = childNode {
                flush()
                groups.append(.eventRef(uri))
            } else {
                pendingChildren.append(child)
            }
        }
        if pendingChildren.count > startCount {
            pendingChildren.append(nostrContentNewlineSentinel)
        }
    }

    for root in tree.roots {
        guard let node = tree.node(at: root) else { continue }
        switch node {
        case .paragraph(let children):
            appendInline(level: .paragraph, children: children)
        case .heading(let level, let children):
            flush()
            appendInline(level: .heading(level: level), children: children)
            flush()
        case .media(let urls, let kind):
            flush()
            groups.append(.media(urls: urls, kind: kind))
        case .eventRef(let uri):
            flush()
            groups.append(.eventRef(uri))
        case .codeBlock(let info, let body):
            flush()
            groups.append(.codeBlock(info: info, body: body))
        case .blockQuote(let children):
            flush()
            groups.append(.blockQuote(children: children))
        case .list(let orderedStart, let items):
            flush()
            groups.append(.list(orderedStart: orderedStart, items: items))
        case .rule:
            flush()
            groups.append(.rule)
        case .image(let alt, let title, let src):
            flush()
            groups.append(.image(alt: alt, title: title, src: src))
        case .placeholder(let reason):
            flush()
            groups.append(.placeholder(reason: reason))
        default:
            // Bare inline node sitting at the root (e.g. plain text with no
            // surrounding paragraph). Treat it as a one-child paragraph.
            appendInline(level: .paragraph, children: [root])
        }
    }
    flush()
    return groups
}

